CREATE EXTENSION IF NOT EXISTS pgcrypto;
-- Fixed UUIDs so other services can seed related records. INSERT INTO users (id, username, password, email, is_active, created_at, updated_at) VALUES ( '00000000-0000-0000-0000-000000000001', 'testowner', crypt('Test1234!', gen_salt('bf')), 'testowner@example.com', TRUE, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP );
-- Assign STORE_OWNER role to the test user INSERT INTO user_roles (user_id, role_id) SELECT '00000000-0000-0000-0000-000000000001', r.id FROM roles r WHERE r.name = 'STORE_OWNER';
